CREATE OR REPLACE FUNCTION fpa_tel_get_bank_no_by_appno (as_appno char) RETURNS SC_MEM_M_APP_BANK_ACCNO.BANK_ACC_NO%TYPE AS $body$
DECLARE

  ls_bank_accno sc_mem_m_app_bank_accno.bank_acc_no%type;

BEGIN

  SELECT sc_mem_m_app_bank_accno.bank_acc_no  into STRICT ls_bank_accno
  FROM sc_mem_m_app_bank_accno
  WHERE sc_mem_m_app_bank_accno.application_form_no = as_appno;

  if coalesce(ls_bank_accno::text, '') = '' then ls_bank_accno := ' ';end if;
return ls_bank_accno;

end;
